	}))

	ps, err := Load(store, "proj", t.TempDir())
	require.NoError(t, err)
	assert.Len(t, ps.Plans, 2)
	assert.Equal(t, StatusReady, ps.Plans["my-plan.md"].Status)
	assert.Equal(t, StatusDone, ps.Plans["done-plan.md"].Status)
