func (s *SQLiteStore) Create(project string, entry PlanEntry) error {
	const q = `
		INSERT INTO plans (project, filename, status, description, branch, topic, created_at, implemented, content, clickup_task_id, review_cycle)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
	`
	_, err := s.db.Exec(q,
		project,
		entry.Filename,
