	result := make([]PlanInfo, 0, len(ps.Plans))
	for filename, entry := range ps.Plans {
		result = append(result, PlanInfo{
			Filename:    filename,
			Status:      entry.Status,
			Description: entry.Description,
			Branch:      entry.Branch,
			Topic:       entry.Topic,
			CreatedAt:   entry.CreatedAt,
		})
