	}
	entry.Branch = branch
	ps.Plans[filename] = entry
	if err := ps.store.Update(ps.project, filename, ps.toPlanstoreEntry(filename, entry)); err != nil {
		return fmt.Errorf("plan store: %w", err)
	}
	return nil
}

